-- Function trả SETOF (streaming result)
CREATE OR REPLACE FUNCTION get_user_order_summary(p_user_id INT)
RETURNS TABLE(
    order_id INT, total DECIMAL, status TEXT, item_count BIGINT
) AS $$
BEGIN
    RETURN QUERY
    SELECT o.id, o.total, o.status, COUNT(oi.id) AS item_count
    FROM orders o
    LEFT JOIN order_items oi ON o.id = oi.order_id
    WHERE o.user_id = p_user_id
    GROUP BY o.id, o.total, o.status;
END;
$$ LANGUAGE plpgsql STABLE;  -- STABLE: không modify DB

-- Complex business logic
CREATE OR REPLACE PROCEDURE process_order_batch(p_batch_id INT)
AS $$
DECLARE
    v_order RECORD;
    v_count INT := 0;
BEGIN
    FOR v_order IN
        SELECT id, total FROM orders WHERE batch_id = p_batch_id AND status = 'pending'
    LOOP
        -- Multiple operations per order (1 trip to DB total)
        UPDATE orders SET status = 'processing' WHERE id = v_order.id;
        INSERT INTO order_audit (order_id, action) VALUES (v_order.id, 'processing');
        v_count := v_count + 1;
    END LOOP;
    RAISE NOTICE 'Processed % orders', v_count;
END;
$$ LANGUAGE plpgsql;

-- CALL procedure từ application
CALL process_order_batch(42);

-- Trigger function
CREATE OR REPLACE FUNCTION update_order_total() RETURNS TRIGGER AS $$
BEGIN
    UPDATE orders SET total = (SELECT SUM(subtotal) FROM order_items WHERE order_id = NEW.order_id)
    WHERE id = NEW.order_id;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
